#!/usr/bin/env python3
"""
Move files generated by mdsplit into the appropriate subfolders.
Matches if the filename starts with a known prefix.
Also fixes filenames that start with a dash (e.g., -real-world-impact.md).
"""

import shutil
import re
from pathlib import Path

DOCS_DIR = Path("mkdocs")

# Mapping: prefix (lowercase) → destination folder
MAPPING = {
    # Getting Started
    "getting-started": "getting-started",
    "installation": "getting-started",
    "choose-your-path": "getting-started",
    "the-transformation": "getting-started",
    "quick-start-scenarios": "getting-started",
    "quick-start": "getting-started",
    "ready-to-transform-your-error-handling": "getting-started",  # call‑to‑action

    # Core Concepts
    "core-concepts": "core-concepts",
    "reslava.result-core-library": "core-concepts",          # main core library file
    "result-pattern": "core-concepts",
    "functional-composition": "core-concepts",
    "async-patterns": "core-concepts",
    "linq-integration": "core-concepts",
    "validation-attributes": "core-concepts",
    "validation-rules": "core-concepts",
    "validation": "core-concepts",
    "maybe": "core-concepts",
    "oneof": "core-concepts",
    "domain-errors": "core-concepts",
    "error-context": "core-concepts",
    "error-types": "core-concepts",
    "performance": "core-concepts",
    "advanced-patterns": "core-concepts",

    # Code examples
    "quick-examples": "code-examples",
    "sample-apps": "code-examples",
    "examples": "code-examples/samples",

    # ASP.NET
    "aspnet": "aspnet",
    "asp.net-integration": "aspnet",                         # note: original had dot
    "minimal-api": "aspnet",
    "mvc": "aspnet",
    "smartendpoints": "aspnet",
    "openapi": "aspnet",
    "authorization": "aspnet",
    "problem-details": "aspnet",
    "oneof-to-iresult": "aspnet",
    "one-of-to-iresult": "aspnet",
    "oneof--iresult": "aspnet",                              # mdsplit strips → character

    # Architecture
    "architecture": "architecture",
    "complete-architecture": "architecture",
    "package-structure": "architecture",
    "how-generators-work": "architecture",
    "reslava.result.sourcegenerators": "architecture",
    "generators": "architecture",
    "solid-architecture": "architecture/solid",
    "uml-v1.12.1-core": "architecture/solid",
    "uml-v1.12.1-generators": "architecture/solid",
    "uml-v1.25.0-core": "architecture/solid",
    "uml-v1.25.0-generators": "architecture/solid",

    # Testing & Quality
    "testing": "testing",
    "test-suite": "testing",
    "ci-cd": "testing",
    "real-world-impact": "testing",
    "production-benefits": "testing",
    "safety-analyzers": "testing",
    "roslyn-analyzers": "testing",

    # Reference
    "reference": "reference",    
    "version-history": "reference",
    "roadmap": "reference",
    "overview": "reference/api-doc",

    # Community
    "contributing": "community",
    "contributors": "community",
    "license": "community",
    "acknowledgments": "community",

    # Others (catch‑all if needed, but better to be explicit)
    "why-choose-reslava.result": "testing",                   # moved to testing/production-benefits
}

def fix_dash_filenames(docs_dir):
    """Rename any file starting with '-' to remove the leading dash."""
    for file in docs_dir.glob("*.md"):
        if file.name.startswith('-'):
            new_name = file.name.lstrip('-')
            new_path = file.with_name(new_name)
            print(f"✂️  Renaming {file.name} → {new_name}")
            file.rename(new_path)

def main():
    if not DOCS_DIR.exists():
        print("❌ docs/ directory not found.")
        return

    # First, fix filenames that start with a dash
    fix_dash_filenames(DOCS_DIR)

    # Collect all markdown files (excluding index.md)
    files = [f for f in DOCS_DIR.glob("*.md") if f.name != "index.md"]

    for file in files:
        stem = file.stem.lower()
        matched = False

        # Try to find a matching prefix (longest first)
        for prefix in sorted(MAPPING.keys(), key=len, reverse=True):
            if stem.startswith(prefix):
                dest_folder = DOCS_DIR / MAPPING[prefix]
                dest_folder.mkdir(exist_ok=True)
                dest_path = dest_folder / file.name
                print(f"Moving {file} -> {dest_path}")
                shutil.move(str(file), str(dest_path))
                matched = True
                break

        if not matched:
            print(f"⚠️  Warning: No matching prefix for {file.name}, leaving in docs/")

if __name__ == "__main__":
    main()